#include <stdio.h>
#include <math.h>
#define MAX_N 500
#define MAX_K 500
#define MAX_COORD 1000000000
#define MAX_SPELL 1000000

int N, K;
int Ax, Ay, Bx, By, Cx, Cy;
int x[MAX_N], y[MAX_N];

double distance(int x1, int y1, int x2, int y2) {
    return sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
}

double calculate_circumference(int Ax, int Ay) {
    return distance(Ax, Ay, Bx, By) + distance(Bx, By, Cx, Cy) + distance(Cx, Cy, Ax, Ay);
}

int main() {
    scanf("%d %d", &N, &K);
    scanf("%d %d", &Ax, &Ay);
    scanf("%d %d", &Bx, &By);
    scanf("%d %d", &Cx, &Cy);
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &x[i], &y[i]);
    }
    double max_circumference = 0;
    for (int mask = 0; mask < (1 << N); mask++) {
        if (__builtin_popcount(mask) <= K) {
            int curr_Ax = Ax, curr_Ay = Ay;
            for (int i = 0; i < N; i++) {
                if ((mask & (1 << i)) != 0) {
                    curr_Ax += x[i];
                    curr_Ay += y[i];
                }
            }
            double circumference = calculate_circumference(curr_Ax, curr_Ay);
            max_circumference = fmax(max_circumference, circumference);
        }
    }
    printf("%.13f\n", max_circumference);
    return 0;
}

