import java.util.Scanner;
import java.lang.Math;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int K = scanner.nextInt();
        int Ax = scanner.nextInt();
        int Ay = scanner.nextInt();
        int Bx = scanner.nextInt();
        int By = scanner.nextInt();
        int Cx = scanner.nextInt();
        int Cy = scanner.nextInt();
        int[] x = new int[N];
        int[] y = new int[N];
        for (int i = 0; i < N; i++) {
            x[i] = scanner.nextInt();
            y[i] = scanner.nextInt();
        }
        double max_circumference = 0;
        for (int mask = 0; mask < (1 << N); mask++) {
            int count = Integer.bitCount(mask);
            if (count <= K) {
                int curr_Ax = Ax, curr_Ay = Ay;
                for (int i = 0; i < N; i++) {
                    if ((mask & (1 << i)) != 0) {
                        curr_Ax += x[i];
                        curr_Ay += y[i];
                    }
                }
                double circumference = calculate_circumference(curr_Ax, curr_Ay, Bx, By, Cx, Cy);
                max_circumference = Math.max(max_circumference, circumference);
            }
        }
        System.out.printf("%.13f\n", max_circumference);
    }
    public static double calculate_circumference(int Ax, int Ay, int Bx, int By, int Cx, int Cy) {
        return distance(Ax, Ay, Bx, By) + distance(Bx, By, Cx, Cy) + distance(Cx, Cy, Ax, Ay);
    }
    public static double distance(int x1, int y1, int x2, int y2) {
        return Math.sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
    }
}

